{"content": "     1|import yaml from "yaml";
     2|import { QueueFrontmatterSchema } from "./schemas.js";
     3|import type { QueueFrontmatter, ParseResult } from "./types.js";
     4|
     5|export interface QueueEntry {
     6|  taskId: string;
     7|  metadata: Record<string, string>;
     8|}
     9|
    10|export interface ParsedQueue {
    11|  frontmatter: QueueFrontmatter | null;
    12|  available: QueueEntry[];
    13|  claimed: QueueEntry[];
    14|  done: QueueEntry[];
    15|  blocked: QueueEntry[];
    16|}
    17|
    18|/** Parse bracket metadata like `[key: value, key2: value2]` from a line fragment. */
    19|function parseBracketMetadata(text: string): Record<string, string> {
    20|  const metadata: Record<string, string> = {};
    21|  const bracketPattern = /\[([^\]]+)\]/g;
    22|  let match: RegExpExecArray | null;
    23|
    24|  while ((match = bracketPattern.exec(text)) !== null) {
    25|    const inner = match[1];
    26|    // Split by comma, but only start a new key-value pair when the segment contains a colon.
    27|    // Segments without a colon are appended to the previous value (e.g. "capabilities: code, testing").
    28|    const segments = inner.split(",");
    29|    let currentKey = "";
    30|    let currentValue = "";
    31|
    32|    for (const segment of segments) {
    33|      const colonIdx = segment.indexOf(":");
    34|      if (colonIdx !== -1 && /^\s*\w+\s*:/.test(segment)) {
    35|        // Flush previous pair
    36|        if (currentKey) {
    37|          metadata[currentKey] = currentValue;
    38|        }
    39|        currentKey = segment.slice(0, colonIdx).trim();
    40|        currentValue = segment.slice(colonIdx + 1).trim();
    41|      } else if (currentKey) {
    42|        // No colon -- continuation of previous value (e.g. "code, testing")
    43|        currentValue += `, ${segment.trim()}`;
    44|      }
    45|    }
    46|    // Flush last pair
    47|    if (currentKey) {
    48|      metadata[currentKey] = currentValue;
    49|    }
    50|  }
    51|
    52|  return metadata;
    53|}
    54|
    55|/** Parse trailing `key: value` pairs outside brackets. */
    56|function parseTrailingMetadata(text: string): Record<string, string> {
    57|  // Remove bracket sections first
    58|  const withoutBrackets = text.replace(/\[[^\]]*\]/g, "");
    59|  const metadata: Record<string, string> = {};
    60|  const trailingPattern = /(\w+):\s*(\S+)/g;
    61|  let match: RegExpExecArray | null;
    62|
    63|  while ((match = trailingPattern.exec(withoutBrackets)) !== null) {
    64|    metadata[match[1]] = match[2];
    65|  }
    66|
    67|  return metadata;
    68|}
    69|
    70|/** Parse list items in a section into QueueEntry objects. */
    71|function parseSectionEntries(sectionContent: string): QueueEntry[] {
    72|  const entries: QueueEntry[] = [];
    73|  const lines = sectionContent.split("\n");
    74|  const taskPattern = /^\s*-\s+(TASK-\d+)\s*(.*)/;
    75|
    76|  for (const line of lines) {
    77|    const match = taskPattern.exec(line);
    78|    if (!match) {
    79|      continue;
    80|    }
    81|
    82|    const taskId = match[1];
    83|    const rest = match[2];
    84|
    85|    const bracketMeta = parseBracketMetadata(rest);
    86|    const trailingMeta = parseTrailingMetadata(rest);
    87|
    88|    entries.push({
    89|      taskId,
    90|      metadata: { ...bracketMeta, ...trailingMeta },
    91|    });
    92|  }
    93|
    94|  return entries;
    95|}
    96|
    97|/** Split markdown body into heading-keyed sections (case-insensitive). */
    98|function splitSections(body: string): Record<string, string> {
    99|  const sections: Record<string, string> = {};
   100|  // Split on ## headings, keeping the heading text
   101|  const parts = body.split(/^##\s+(.+)$/im);
   102|
   103|  // parts alternates: [pre-heading-text, heading1, content1, heading2, content2, ...]
   104|  for (let i = 1; i < parts.length; i += 2) {
   105|    const heading = parts[i].trim().toLowerCase();
   106|    const content = parts[i + 1] ?? "";
   107|    sections[heading] = content;
   108|  }
   109|
   110|  return sections;
   111|}
   112|
   113|/**
   114| * Parse queue frontmatter using yaml + Zod schema directly.
   115| * This avoids depending on frontmatter.ts which may not exist yet during parallel builds.
   116| */
   117|function parseQueueFrontmatter(content: string, filePath: string): ParseResult<QueueFrontmatter> {
   118|  const normalized = content.replace(/\r\n/g, "\n").replace(/\r/g, "\n");
   119|  if (!normalized.startsWith("---")) {
   120|    return {
   121|      success: false,
   122|      error: {
   123|        filePath,
   124|        message: "No frontmatter block found",
   125|        issues: [{ path: "", message: "Missing opening ---" }],
   126|      },
   127|    };
   128|  }
   129|
   130|  const endIndex = normalized.indexOf("\n---", 3);
   131|  if (endIndex === -1) {
   132|    return {
   133|      success: false,
   134|      error: {
   135|        filePath,
   136|        message: "Unclosed frontmatter block",
   137|        issues: [{ path: "", message: "Missing closing ---" }],
   138|      },
   139|    };
   140|  }
   141|
   142|  const yamlStr = normalized.slice(4, endIndex);
   143|  try {
   144|    const raw = yaml.parse(yamlStr) ?? {};
   145|    const result = QueueFrontmatterSchema.safeParse(raw);
   146|    if (result.success) {
   147|      return { success: true, data: result.data };
   148|    }
   149|    return {
   150|      success: false,
   151|      error: {
   152|        filePath,
   153|        message: "Queue frontmatter validation failed",
   154|        issues: result.error.issues.map((i) => ({
   155|          path: i.path.join("."),
   156|          message: i.message,
   157|        })),
   158|      },
   159|    };
   160|  } catch (err) {
   161|    return {
   162|      success: false,
   163|      error: {
   164|        filePath,
   165|        message: "YAML parse error",
   166|        issues: [{ path: "", message: err instanceof Error ? err.message : String(err) }],
   167|      },
   168|    };
   169|  }
   170|}
   171|
   172|/**
   173| * Parse a queue.md file into structured sections with typed entries.
   174| *
   175| * Queue format:
   176| * - Optional YAML frontmatter (updated timestamp)
   177| * - Sections: ## Available, ## Claimed, ## Done, ## Blocked
   178| * - List items: `- TASK-003 [capabilities: code, testing] priority: high`
   179| */
   180|export function parseQueue(content: string, filePath: string): ParsedQueue {
   181|  // 1. Parse frontmatter
   182|  const fmResult = parseQueueFrontmatter(content, filePath);
   183|  const frontmatter = fmResult.success ? fmResult.data : null;
   184|
   185|  // 2. Extract body (everything after frontmatter closing triple-dash)
   186|  const normalized = content.replace(/\r\n/g, "\n").replace(/\r/g, "\n");
   187|  let body = normalized;
   188|  if (normalized.startsWith("---")) {
   189|    const endIndex = normalized.indexOf("\n---", 3);
   190|    if (endIndex !== -1) {
   191|      body = normalized.slice(endIndex + 4);
   192|    }
   193|  }
   194|
   195|  // 3. Split body into sections
   196|  const sections = splitSections(body);
   197|
   198|  // 4. Parse each section
   199|  return {
   200|    frontmatter,
   201|    available: parseSectionEntries(sections["available"] ?? ""),
   202|    claimed: parseSectionEntries(sections["claimed"] ?? ""),
   203|    done: parseSectionEntries(sections["done"] ?? ""),
   204|    blocked: parseSectionEntries(sections["blocked"] ?? ""),
   205|  };
   206|}
   207|", "total_lines": 206, "file_size": 6268, "truncated": false, "is_binary": false, "is_image": false}

{"content": "     1|import fs from "node:fs/promises";
     2|import path from "node:path";
     3|import yaml from "yaml";
     4|import { withFileLock, type FileLockOptions } from "../plugin-sdk/file-lock.js";
     5|import { parseQueue, type ParsedQueue, type QueueEntry } from "./queue-parser.js";
     6|
     7|/** Lock options tuned for queue operations: 3 retries with exponential backoff, 60s stale. */
     8|export const QUEUE_LOCK_OPTIONS: FileLockOptions = {
     9|  retries: {
    10|    retries: 3,
    11|    factor: 2,
    12|    minTimeout: 50,
    13|    maxTimeout: 200,
    14|    randomize: true,
    15|  },
    16|  stale: 60_000,
    17|};
    18|
    19|export class QueueLockError extends Error {
    20|  constructor(projectDir: string) {
    21|    super(`Queue lock timeout for ${projectDir}`);
    22|    this.name = "QueueLockError";
    23|  }
    24|}
    25|
    26|export class QueueValidationError extends Error {
    27|  constructor(message: string) {
    28|    super(message);
    29|    this.name = "QueueValidationError";
    30|  }
    31|}
    32|
    33|export type QueueSection = "available" | "claimed" | "done" | "blocked";
    34|
    35|const SECTION_HEADINGS: Record<QueueSection, string> = {
    36|  available: "Available",
    37|  claimed: "Claimed",
    38|  done: "Done",
    39|  blocked: "Blocked",
    40|};
    41|
    42|/** Serialize a ParsedQueue back to markdown, round-tripping with parseQueue. */
    43|export function serializeQueue(parsed: ParsedQueue): string {
    44|  let out = "";
    45|
    46|  // Frontmatter
    47|  if (parsed.frontmatter) {
    48|    const yamlStr = yaml.stringify(parsed.frontmatter, { schema: "core" });
    49|    out += `---\n${yamlStr}---\n`;
    50|  }
    51|
    52|  // Sections in canonical order
    53|  const sections: QueueSection[] = ["available", "claimed", "done", "blocked"];
    54|  for (const section of sections) {
    55|    out += `\n## ${SECTION_HEADINGS[section]}\n`;
    56|    const entries: QueueEntry[] = parsed[section];
    57|    if (entries.length > 0) {
    58|      out += "\n";
    59|      for (const entry of entries) {
    60|        out += serializeEntry(entry);
    61|      }
    62|    }
    63|  }
    64|
    65|  return out;
    66|}
    67|
    68|/** Format a single queue entry as a markdown list item. */
    69|function serializeEntry(entry: QueueEntry): string {
    70|  const keys = Object.keys(entry.metadata);
    71|  if (keys.length === 0) {
    72|    return `- ${entry.taskId}\n`;
    73|  }
    74|  const pairs = keys.map((k) => `${k}: ${entry.metadata[k]}`).join(", ");
    75|  return `- ${entry.taskId} [${pairs}]\n`;
    76|}
    77|
    78|/**
    79| * Find and remove a task from a section, returning the entry.
    80| * Throws QueueValidationError if the task is not found.
    81| */
    82|function takeEntry(
    83|  entries: QueueEntry[],
    84|  taskId: string,
    85|  sectionName: string,
    86|): { entry: QueueEntry; remaining: QueueEntry[] } {
    87|  const idx = entries.findIndex((e) => e.taskId === taskId);
    88|  if (idx === -1) {
    89|    throw new QueueValidationError(`Task ${taskId} not found in ${sectionName} section`);
    90|  }
    91|  const entry = entries[idx];
    92|  const remaining = [...entries.slice(0, idx), ...entries.slice(idx + 1)];
    93|  return { entry, remaining };
    94|}
    95|
    96|/**
    97| * Manages concurrent access to a project's queue.md file.
    98| * All mutating methods hold a file lock for the entire read-modify-write cycle
    99| * and validate persistence by re-reading after write.
   100| */
   101|export class QueueManager {
   102|  private readonly queuePath: string;
   103|
   104|  constructor(private readonly projectDir: string) {
   105|    this.queuePath = path.join(projectDir, "queue.md");
   106|  }
   107|
   108|  /** Read and parse queue.md without acquiring a lock. */
   109|  async readQueue(): Promise<ParsedQueue> {
   110|    const content = await fs.readFile(this.queuePath, "utf8");
   111|    return parseQueue(content, this.queuePath);
   112|  }
   113|
   114|  /**
   115|   * Lock-protected read-modify-write with post-write validation.
   116|   * Catches file-lock timeout errors and wraps them as QueueLockError.
   117|   */
   118|  private async lockedWriteOp(
   119|    op: (parsed: ParsedQueue) => ParsedQueue,
   120|    validationCheck: (result: ParsedQueue) => void,
   121|  ): Promise<void> {
   122|    try {
   123|      await withFileLock(this.queuePath, QUEUE_LOCK_OPTIONS, async () => {
   124|        // Read
   125|        const content = await fs.readFile(this.queuePath, "utf8");
   126|        const parsed = parseQueue(content, this.queuePath);
   127|
   128|        // Modify
   129|        const updated = op(parsed);
   130|
   131|        // Update frontmatter timestamp
   132|        if (updated.frontmatter) {
   133|          updated.frontmatter.updated = new Date().toISOString().split("T")[0];
   134|        }
   135|
   136|        // Write
   137|        const serialized = serializeQueue(updated);
   138|        await fs.writeFile(this.queuePath, serialized, "utf8");
   139|
   140|        // Re-read and validate persistence
   141|        const reReadContent = await fs.readFile(this.queuePath, "utf8");
   142|        const reRead = parseQueue(reReadContent, this.queuePath);
   143|        validationCheck(reRead);
   144|      });
   145|    } catch (err) {
   146|      // Rethrow known error types as-is
   147|      if (err instanceof QueueValidationError || err instanceof QueueLockError) {
   148|        throw err;
   149|      }
   150|      // Wrap file-lock timeout errors
   151|      if (err instanceof Error && err.message.includes("file lock timeout")) {
   152|        throw new QueueLockError(this.projectDir);
   153|      }
   154|      throw err;
   155|    }
   156|  }
   157|
   158|  /** Move a task from Available to Claimed with agent metadata. */
   159|  async claimTask(taskId: string, agentId: string): Promise<void> {
   160|    await this.lockedWriteOp(
   161|      (parsed) => {
   162|        const { entry, remaining } = takeEntry(parsed.available, taskId, "Available");
   163|        return {
   164|          ...parsed,
   165|          available: remaining,
   166|          claimed: [
   167|            ...parsed.claimed,
   168|            {
   169|              taskId: entry.taskId,
   170|              metadata: {
   171|                ...entry.metadata,
   172|                agent: agentId,
   173|                claimed: new Date().toISOString(),
   174|              },
   175|            },
   176|          ],
   177|        };
   178|      },
   179|      (reRead) => {
   180|        if (!reRead.claimed.some((e) => e.taskId === taskId)) {
   181|          throw new QueueValidationError(
   182|            `Post-write validation failed: ${taskId} not found in Claimed`,
   183|          );
   184|        }
   185|      },
   186|    );
   187|  }
   188|
   189|  /** Move a task from Claimed back to Available, stripping agent metadata. */
   190|  async releaseTask(taskId: string): Promise<void> {
   191|    await this.lockedWriteOp(
   192|      (parsed) => {
   193|        const { entry, remaining } = takeEntry(parsed.claimed, taskId, "Claimed");
   194|        // Strip agent and claimed keys from metadata
   195|        const { agent: _a, claimed: _c, ...cleanMeta } = entry.metadata;
   196|        return {
   197|          ...parsed,
   198|          claimed: remaining,
   199|          available: [...parsed.available, { taskId: entry.taskId, metadata: cleanMeta }],
   200|        };
   201|      },
   202|      (reRead) => {
   203|        if (!reRead.available.some((e) => e.taskId === taskId)) {
   204|          throw new QueueValidationError(
   205|            `Post-write validation failed: ${taskId} not found in Available`,
   206|          );
   207|        }
   208|      },
   209|    );
   210|  }
   211|
   212|  /** Move a task between arbitrary sections. */
   213|  async moveTask(
   214|    taskId: string,
   215|    fromSection: QueueSection,
   216|    toSection: QueueSection,
   217|  ): Promise<void> {
   218|    await this.lockedWriteOp(
   219|      (parsed) => {
   220|        const { entry, remaining } = takeEntry(
   221|          parsed[fromSection],
   222|          taskId,
   223|          SECTION_HEADINGS[fromSection],
   224|        );
   225|        return {
   226|          ...parsed,
   227|          [fromSection]: remaining,
   228|          [toSection]: [...parsed[toSection], entry],
   229|        };
   230|      },
   231|      (reRead) => {
   232|        if (!reRead[toSection].some((e) => e.taskId === taskId)) {
   233|          throw new QueueValidationError(
   234|            `Post-write validation failed: ${taskId} not found in ${SECTION_HEADINGS[toSection]}`,
   235|          );
   236|        }
   237|      },
   238|    );
   239|  }
   240|}
