{"content": "     1|import { rename, readFile, writeFile } from "node:fs/promises";
     2|
     3|/**
     4| * Checkpoint data persisted alongside each task markdown file.
     5| * Enables agent resume after context compaction by recording
     6| * progress, failed approaches, and next actions.
     7| */
     8|export interface CheckpointData {
     9|  status: "in-progress" | "review" | "done" | "blocked";
    10|  claimed_by: string;
    11|  claimed_at: string;
    12|  last_step: string;
    13|  next_action: string;
    14|  progress_pct: number;
    15|  files_modified: string[];
    16|  failed_approaches: Array<{ approach: string; reason: string }>;
    17|  log: Array<{ timestamp: string; agent: string; action: string }>;
    18|  notes: string;
    19|}
    20|
    21|/**
    22| * Derive the checkpoint sidecar path from a task markdown path.
    23| * Example: "tasks/TASK-005.md" -> "tasks/TASK-005.checkpoint.json"
    24| */
    25|export function checkpointPath(taskFilePath: string): string {
    26|  return taskFilePath.replace(/\.md$/, ".checkpoint.json");
    27|}
    28|
    29|/**
    30| * Create initial checkpoint data when a task is claimed.
    31| */
    32|export function createCheckpoint(opts: {
    33|  agentId: string;
    34|  taskId: string;
    35|  timestamp?: string;
    36|}): CheckpointData {
    37|  const claimedAt = opts.timestamp ?? new Date().toISOString();
    38|  return {
    39|    status: "in-progress",
    40|    claimed_by: opts.agentId,
    41|    claimed_at: claimedAt,
    42|    last_step: "",
    43|    next_action: "",
    44|    progress_pct: 0,
    45|    files_modified: [],
    46|    failed_approaches: [],
