    55| */
    56|export async function writeCheckpoint(filePath: string, data: CheckpointData): Promise<void> {
    57|  const tmpPath = `${filePath}.tmp`;
    58|  await writeFile(tmpPath, JSON.stringify(data, null, "\t"), "utf-8");
