    64| * does not exist or contains corrupted JSON (graceful degradation).
    65| */
    66|export async function readCheckpoint(filePath: string): Promise<CheckpointData | null> {
    67|  try {
    68|    const raw = await readFile(filePath, "utf-8");
    69|    return JSON.parse(raw) as CheckpointData;
    70|  } catch (err: unknown) {
    71|    if (err instanceof SyntaxError) {
    72|      // Corrupted JSON -- warn but don't throw
    73|      console.warn(`[checkpoint] corrupted checkpoint file: ${filePath}`);
    74|      return null;
    75|    }
    76|    if (isNodeError(err) && err.code === "ENOENT") {
    77|      return null;
    78|    }
    79|    throw err;
    80|  }
    81|}
    82|
    83|/** Type guard for Node.js filesystem errors with a `code` property. */
    84|function isNodeError(err: unknown): err is NodeJS.ErrnoException {
