{"content": "     1|import fs from "node:fs/promises";
     2|import path from "node:path";
     3|import { createSubsystemLogger } from "../logging/subsystem.js";
     4|import { matchCapabilities } from "./capability-matcher.js";
     5|import {
     6|  type CheckpointData,
     7|  checkpointPath,
     8|  createCheckpoint,
     9|  readCheckpoint,
    10|  writeCheckpoint,
    11|} from "./checkpoint.js";
    12|import { parseTaskFrontmatter } from "./frontmatter.js";
    13|import { QueueManager } from "./queue-manager.js";
    14|import type { TaskFrontmatter } from "./types.js";
    15|
    16|const log = createSubsystemLogger("projects/heartbeat-scanner");
    17|
    18|// -- Scanner types --
    19|
    20|export type ScanAndClaimResult =
    21|  | { type: "idle" }
    22|  | {
    23|      type: "claimed";
    24|      task: { id: string; path: string; content: string };
    25|      checkpoint: CheckpointData;
    26|    }
    27|  | {
    28|      type: "resumed";
    29|      task: { id: string; path: string; content: string };
    30|      checkpoint: CheckpointData;
    31|    };
    32|
    33|export interface ScanAndClaimOpts {
    34|  agentId: string;
    35|  agentCapabilities: string[];
    36|  projectDir: string;
    37|}
    38|
    39|/** Priority ordering: lower number = higher priority. */
    40|const PRIORITY_ORDER: Record<string, number> = {
    41|  critical: 0,
    42|  high: 1,
    43|  medium: 2,
    44|  low: 3,
    45|};
    46|
    47|// -- Core scanner --
    48|
    49|/**
    50| * Scan for an active task to resume or a new task to claim from the queue.
    51| *
    52| * Algorithm:
    53| * 1. Check for active checkpoint (short-circuit resume)
    54| * 2. Read queue.md Available entries
    55| * 3. Filter by capabilities and dependency satisfaction
    56| * 4. Sort by priority (critical > high > medium > low), then queue position
    57| * 5. Claim highest priority match
    58| * 6. Return idle if nothing claimable
    59| *
    60| * Never throws -- always returns a result.
    61| */
    62|export async function scanAndClaimTask(opts: ScanAndClaimOpts): Promise<ScanAndClaimResult> {
    63|  const { agentId, agentCapabilities, projectDir } = opts;
    64|
    65|  // Step 1: Check for active checkpoint (resume short-circuit)
    66|  const resumed = await findActiveCheckpoint(projectDir, agentId);
    67|  if (resumed) {
    68|    return resumed;
    69|  }
    70|
    71|  // Step 2-5: Scan queue and claim
    72|  try {
    73|    const qm = new QueueManager(projectDir);
    74|    const queue = await qm.readQueue();
    75|
    76|    if (queue.available.length === 0) {
    77|      return { type: "idle" };
    78|    }
    79|
    80|    // Step 3: Filter claimable tasks
    81|    const claimable = await filterClaimableTasks(
    82|      queue.available.map((e) => e.taskId),
    83|      projectDir,
    84|      agentCapabilities,
    85|    );
    86|
    87|    if (claimable.length === 0) {
    88|      return { type: "idle" };
    89|    }
    90|
    91|    // Step 4: Sort by priority, preserve queue position for ties
    92|    // claimable is already in queue order from filterClaimableTasks,
    93|    // so a stable sort by priority preserves positional tiebreak.
    94|    const sorted = sortByPriority(claimable);
    95|
    96|    // Step 5: Claim the top task
    97|    const best = sorted[0];
    98|    const taskFilePath = path.join(projectDir, "tasks", `${best.id}.md`);
    99|    const content = await fs.readFile(taskFilePath, "utf8");
   100|
   101|    await qm.claimTask(best.id, agentId);
   102|
   103|    const checkpoint = createCheckpoint({ agentId, taskId: best.id });
   104|    const cpPath = checkpointPath(taskFilePath);
   105|    await writeCheckpoint(cpPath, checkpoint);
   106|
   107|    return {
   108|      type: "claimed",
   109|      task: { id: best.id, path: taskFilePath, content },
   110|      checkpoint,
   111|    };
   112|  } catch (err) {
   113|    log.warn("Queue scan failed, returning idle", {
   114|      error: err instanceof Error ? err.message : String(err),
   115|      projectDir,
   116|    });
   117|    return { type: "idle" };
   118|  }
   119|}
   120|
   121|// -- Helpers --
   122|
   123|/** Scan tasks/ directory for an active checkpoint belonging to this agent. */
   124|async function findActiveCheckpoint(
   125|  projectDir: string,
   126|  agentId: string,
   127|): Promise<ScanAndClaimResult | null> {
   128|  const tasksDir = path.join(projectDir, "tasks");
   129|
   130|  let entries: string[];
   131|  try {
   132|    entries = await fs.readdir(tasksDir);
   133|  } catch {
   134|    return null;
   135|  }
   136|
   137|  const cpFiles = entries.filter((f) => f.endsWith(".checkpoint.json"));
   138|  for (const cpFile of cpFiles) {
   139|    const cpFilePath = path.join(tasksDir, cpFile);
   140|    const checkpoint = await readCheckpoint(cpFilePath);
   141|
   142|    // Skip corrupted or non-matching checkpoints
   143|    if (!checkpoint) {
   144|      continue;
   145|    }
   146|    if (checkpoint.claimed_by !== agentId) {
   147|      continue;
   148|    }
   149|    if (checkpoint.status !== "in-progress") {
   150|      continue;
   151|    }
   152|
   153|    // Found an active task -- read the matching .md file
   154|    const taskId = cpFile.replace(".checkpoint.json", "");
   155|    const taskFilePath = path.join(tasksDir, `${taskId}.md`);
   156|
   157|    try {
   158|      const content = await fs.readFile(taskFilePath, "utf8");
   159|      return {
   160|        type: "resumed",
   161|        task: { id: taskId, path: taskFilePath, content },
   162|        checkpoint,
   163|      };
   164|    } catch {
   165|      log.warn("Active checkpoint found but task file missing", { taskId, agentId });
   166|      continue;
   167|    }
   168|  }
   169|
   170|  return null;
   171|}
   172|
   173|/**
   174| * Filter available task IDs to those claimable by this agent.
   175| * Preserves input order (queue position) for downstream stable sort.
   176| */
   177|async function filterClaimableTasks(
   178|  taskIds: string[],
   179|  projectDir: string,
   180|  agentCapabilities: string[],
   181|): Promise<Array<{ id: string; priority: string }>> {
   182|  const claimable: Array<{ id: string; priority: string }> = [];
   183|  const tasksDir = path.join(projectDir, "tasks");
   184|
   185|  for (const taskId of taskIds) {
   186|    const taskFilePath = path.join(tasksDir, `${taskId}.md`);
   187|
   188|    let content: string;
   189|    try {
   190|      content = await fs.readFile(taskFilePath, "utf8");
   191|    } catch {
   192|      log.warn("Task file not found, skipping", { taskId });
   193|      continue;
   194|    }
   195|
   196|    const result = parseTaskFrontmatter(content, taskFilePath);
   197|    if (!result.success) {
   198|      log.warn("Task frontmatter parse failed, skipping", { taskId });
   199|      continue;
   200|    }
   201|
   202|    const fm: TaskFrontmatter = result.data;
   203|
   204|    // Capability check
   205|    if (!matchCapabilities(agentCapabilities, fm.capabilities)) {
   206|      continue;
   207|    }
   208|
   209|    // Dependency check: ALL depends_on must be "done"
   210|    if (fm.depends_on.length > 0) {
   211|      const allDone = await checkAllDepsDone(fm.depends_on, tasksDir);
   212|      if (!allDone) {
   213|        continue;
   214|      }
   215|    }
   216|
   217|    claimable.push({ id: taskId, priority: fm.priority });
   218|  }
   219|
   220|  return claimable;
   221|}
   222|
   223|/** Check that every dependency task has status "done". */
   224|async function checkAllDepsDone(depIds: string[], tasksDir: string): Promise<boolean> {
   225|  for (const depId of depIds) {
   226|    const depPath = path.join(tasksDir, `${depId}.md`);
   227|    try {
   228|      const content = await fs.readFile(depPath, "utf8");
   229|      const result = parseTaskFrontmatter(content, depPath);
   230|      if (!result.success || result.data.status !== "done") {
   231|        return false;
   232|      }
   233|    } catch {
   234|      // Missing dep file = not done (safe default)
   235|      return false;
   236|    }
   237|  }
   238|  return true;
   239|}
   240|
   241|/** Stable sort by priority (critical > high > medium > low). */
   242|function sortByPriority(
   243|  tasks: Array<{ id: string; priority: string }>,
   244|): Array<{ id: string; priority: string }> {
   245|  // Slice to avoid mutating input, then stable sort
   246|  return [...tasks].toSorted((a, b) => {
   247|    const pa = PRIORITY_ORDER[a.priority] ?? 3;
   248|    const pb = PRIORITY_ORDER[b.priority] ?? 3;
   249|    return pa - pb;
   250|  });
   251|}
