    45|
    46|    // Ensure parent exists, then atomic mkdir for the project dir itself
    47|    await fs.mkdir(this.projectsRoot, { recursive: true });
    48|    try {
    49|      await fs.mkdir(projectDir);
    50|    } catch (err: unknown) {
    51|      if ((err as NodeJS.ErrnoException).code === "EEXIST") {
    52|        throw new Error(`Project already exists at ${projectDir}`, { cause: err });
    53|      }
    54|      throw err;
    55|    }
    56|
    57|    // Create tasks/ with .gitkeep
    58|    const tasksDir = path.join(projectDir, "tasks");
    59|    await fs.mkdir(tasksDir, { recursive: true });
    60|    await fs.writeFile(path.join(tasksDir, ".gitkeep"), "", "utf-8");
    61|
