    65|
    66|    return projectDir;
    67|  }
    68|
    69|  /**
    70|   * Create a sub-project one level deep under a parent project.
    71|   * Sub-projects live at `<parent>/sub-projects/<name>/` with the same
    72|   * internal structure (PROJECT.md, queue.md, tasks/.gitkeep).
    73|   */
    74|  async createSubProject(opts: CreateSubProjectOpts): Promise<string> {
