    94|      }
    95|      throw err;
    96|    }
    97|
    98|    // Create tasks/ with .gitkeep
    99|    const tasksDir = path.join(subDir, "tasks");
   100|    await fs.mkdir(tasksDir, { recursive: true });
   101|    await fs.writeFile(path.join(tasksDir, ".gitkeep"), "", "utf-8");
   102|
   103|    // Generate and write PROJECT.md and queue.md atomically
   104|    await writeFileAtomic(
