   107|    );
   108|    await writeFileAtomic(path.join(subDir, "queue.md"), generateQueueMd());
   109|
   110|    return subDir;
   111|  }
   112|
   113|  /**
   114|   * Return the next sequential task ID for a project directory.
   115|   * Scans `tasks/` for existing TASK-NNN.md files, finds the max, and
   116|   * returns max+1 with at least 3-digit zero-padding.
   117|   */
   118|  async nextTaskId(projectDir: string): Promise<string> {
   119|    const tasksDir = path.join(projectDir, "tasks");
   120|    let entries: string[];
   121|    try {
   122|      entries = await fs.readdir(tasksDir);
   123|    } catch {
   124|      // tasks/ doesn't exist — start at 1
   125|      return "TASK-001";
   126|    }
   127|
   128|    const pattern = /^TASK-(\d+)\.md$/;
   129|    let maxId = 0;
   130|    for (const entry of entries) {
   131|      const match = pattern.exec(entry);
   132|      if (match) {
   133|        const num = parseInt(match[1], 10);
   134|        if (num > maxId) {
   135|          maxId = num;
   136|        }
   137|      }
   138|    }
   139|
   140|    const next = maxId + 1;
   141|    return `TASK-${String(next).padStart(3, "0")}`;
   142|  }
   143|}
