{"content": "     1|import { EventEmitter } from "node:events";
     2|import fs from "node:fs/promises";
     3|import path from "node:path";
     4|import chokidar, { type FSWatcher } from "chokidar";
     5|import { parseProjectFrontmatter, parseTaskFrontmatter } from "./frontmatter.js";
     6|import {
     7|  generateAllIndexes,
     8|  generateBoardIndex,
     9|  generateProjectIndex,
    10|  generateQueueIndex,
    11|  generateTaskIndex,
    12|  writeIndexFile,
    13|} from "./index-generator.js";
    14|import { parseQueue } from "./queue-parser.js";
    15|import type { SyncEvent } from "./sync-types.js";
    16|import type { TaskFrontmatter } from "./types.js";
    17|
    18|/**
    19| * Watches project markdown files for changes, debounces updates per-project,
    20| * triggers incremental index regeneration, and performs full reindex on startup.
    21| *
    22| * Emits `"sync"` events (typed as SyncEvent) for downstream consumers
    23| * (Gateway WebSocket, UI).
    24| */
    25|export class ProjectSyncService extends EventEmitter {
    26|  private watcher: FSWatcher | null = null;
    27|  private debounceTimers: Map<string, ReturnType<typeof setTimeout>> = new Map();
    28|  private readonly projectsRoot: string;
    29|
    30|  constructor(projectsRoot: string) {
    31|    super();
    32|    this.projectsRoot = projectsRoot;
    33|  }
    34|
    35|  /**
    36|   * Discover all project directories (those containing PROJECT.md).
    37|   * Checks top-level and one level of sub-projects at `<project>/sub-projects/<child>/`.
    38|   */
    39|  async discoverProjects(): Promise<string[]> {
    40|    const projects: string[] = [];
    41|    let entries: string[] = [];
    42|    try {
    43|      entries = await fs.readdir(this.projectsRoot);
    44|    } catch {
    45|      return projects;
    46|    }
    47|
    48|    for (const entry of entries) {
    49|      const entryPath = path.join(this.projectsRoot, entry);
    50|      const stat = await fs.stat(entryPath).catch(() => null);
    51|      if (!stat?.isDirectory()) {
    52|        continue;
    53|      }
    54|
    55|      // Check if this is a project directory
    56|      const hasProjectMd = await fs
    57|        .access(path.join(entryPath, "PROJECT.md"))
    58|        .then(() => true)
    59|        .catch(() => false);
    60|
    61|      if (hasProjectMd) {
    62|        projects.push(entryPath);
    63|      }
    64|
    65|      // Check for sub-projects
    66|      const subProjectsDir = path.join(entryPath, "sub-projects");
    67|      let subEntries: string[] = [];
    68|      try {
    69|        subEntries = await fs.readdir(subProjectsDir);
    70|      } catch {
    71|        continue;
    72|      }
    73|
    74|      for (const sub of subEntries) {
    75|        const subPath = path.join(subProjectsDir, sub);
    76|        const subStat = await fs.stat(subPath).catch(() => null);
    77|        if (!subStat?.isDirectory()) {
    78|          continue;
    79|        }
    80|
    81|        const subHasProjectMd = await fs
    82|          .access(path.join(subPath, "PROJECT.md"))
    83|          .then(() => true)
    84|          .catch(() => false);
    85|
    86|        if (subHasProjectMd) {
    87|          projects.push(subPath);
    88|        }
    89|      }
    90|    }
    91|
    92|    return projects;
    93|  }
    94|
    95|  /**
    96|   * Run full reindex on all projects, then start watching for changes.
    97|   */
    98|  async start(): Promise<void> {
    99|    // 1. Discover and reindex all projects
   100|    const projectDirs = await this.discoverProjects();
   101|
   102|    for (const projectDir of projectDirs) {
   103|      try {
   104|        const events = await generateAllIndexes(projectDir);
   105|        for (const event of events) {
   106|          this.emit("sync", event);
   107|        }
   108|      } catch (err) {
   109|        this.emit("error", err);
   110|      }
   111|    }
   112|
   113|    // 2. Start chokidar watcher
   114|    this.watcher = chokidar.watch(this.projectsRoot, {
   115|      ignoreInitial: true,
   116|      ignored: [/(^|[/\\])\.index/, /(^|[/\\])\.lock/, /(^|[/\\])node_modules/],
   117|      awaitWriteFinish: {
   118|        stabilityThreshold: 200,
   119|        pollInterval: 100,
   120|      },
   121|      depth: 5,
   122|    });
   123|
   124|    this.watcher.on("add", (filePath: string) => this.handleFileChange(filePath));
   125|    this.watcher.on("change", (filePath: string) => this.handleFileChange(filePath));
   126|    this.watcher.on("unlink", (filePath: string) => this.handleFileDelete(filePath));
   127|  }
   128|
   129|  /**
   130|   * Close watcher and clear all debounce timers.
   131|   */
   132|  async stop(): Promise<void> {
   133|    await this.watcher?.close();
   134|    this.watcher = null;
   135|
   136|    for (const timer of this.debounceTimers.values()) {
   137|      clearTimeout(timer);
   138|    }
   139|    this.debounceTimers.clear();
   140|  }
   141|
   142|  private handleFileChange(filePath: string): void {
   143|    if (!filePath.endsWith(".md")) {
   144|      return;
   145|    }
   146|    const resolved = this.resolveProjectDir(filePath);
   147|    if (!resolved) {
   148|      return;
   149|    }
   150|    this.scheduleUpdate(resolved.projectName, filePath, "change");
   151|  }
   152|
   153|  private handleFileDelete(filePath: string): void {
   154|    if (!filePath.endsWith(".md")) {
   155|      return;
   156|    }
   157|    const resolved = this.resolveProjectDir(filePath);
   158|    if (!resolved) {
   159|      return;
   160|    }
   161|    this.scheduleUpdate(resolved.projectName, filePath, "delete");
   162|  }
   163|
   164|  /**
   165|   * Per-project debounce: batches rapid changes into a single update.
   166|   */
   167|  private scheduleUpdate(projectName: string, filePath: string, action: "change" | "delete"): void {
