   292|  /**
   293|   * Resolve a file path to its project directory and name.
   294|   * Handles both top-level projects and sub-projects.
   295|   */
   296|  private resolveProjectDir(filePath: string): { projectName: string; projectDir: string } | null {
   297|    const relative = path.relative(this.projectsRoot, filePath);
   298|    if (relative.startsWith("..") || path.isAbsolute(relative)) {
   299|      return null;
   300|    }
   301|
   302|    const parts = relative.split(path.sep);
   303|    if (parts.length < 1) {
   304|      return null;
   305|    }
   306|
   307|    // Check if this is a sub-project path: <project>/sub-projects/<child>/...
   308|    if (parts.length >= 3 && parts[1] === "sub-projects") {
   309|      const projectDir = path.join(this.projectsRoot, parts[0], parts[1], parts[2]);
   310|      return { projectName: parts[2], projectDir };
   311|    }
   312|
   313|    // Top-level project: <project>/...
   314|    const projectDir = path.join(this.projectsRoot, parts[0]);
   315|    return { projectName: parts[0], projectDir };
