    14|} from "./sync-types.js";
    15|import type { ProjectFrontmatter, TaskFrontmatter } from "./types.js";
    16|
    17|/**
    18| * Transform parsed project frontmatter into a JSON-serializable ProjectIndex.
    19| */
    20|export function generateProjectIndex(frontmatter: ProjectFrontmatter): ProjectIndex {
    21|  return {
    22|    ...frontmatter,
    23|    indexedAt: new Date().toISOString(),
    24|  };
    25|}
    26|
    27|/**
    28| * Transform parsed task frontmatter into a JSON-serializable TaskIndex.
    29| */
    30|export function generateTaskIndex(frontmatter: TaskFrontmatter): TaskIndex {
    31|  return {
    32|    ...frontmatter,
    33|    indexedAt: new Date().toISOString(),
    34|  };
    35|}
    36|
    37|/**
    38| * Group tasks by their `column` field into the provided column names.
    39| * Tasks with an unknown column fall back to the first column.
    40| */
    41|export function generateBoardIndex(tasks: TaskFrontmatter[], columns: string[]): BoardIndex {
    42|  // Initialize column map
    43|  const columnMap = new Map<string, BoardTaskEntry[]>();
    44|  for (const col of columns) {
    45|    columnMap.set(col, []);
    46|  }
    47|
    48|  for (const task of tasks) {
    49|    const targetColumn = columnMap.has(task.column) ? task.column : columns[0];
    50|    const entry: BoardTaskEntry = {
    51|      id: task.id,
    52|      title: task.title,
    53|      status: task.status,
    54|      priority: task.priority,
    55|      claimed_by: task.claimed_by,
    56|    };
    57|    columnMap.get(targetColumn)!.push(entry);
    58|  }
    59|
    60|  return {
    61|    columns: columns.map((name) => ({
    62|      name,
    63|      tasks: columnMap.get(name)!,
    64|    })),
    65|    indexedAt: new Date().toISOString(),
    66|  };
    67|}
    68|
    69|/**
    70| * Transform a parsed queue into a JSON-serializable QueueIndex.
    71| */
    72|export function generateQueueIndex(parsed: ParsedQueue): QueueIndex {
    73|  return {
    74|    available: parsed.available,
    75|    claimed: parsed.claimed,
    76|    blocked: parsed.blocked,
    77|    done: parsed.done,
    78|    indexedAt: new Date().toISOString(),
    79|  };
    80|}
    81|
    82|/**
    83| * Write JSON data atomically via temp file + rename.
    84| * Ensures no half-written index files on crash (SYNC-05).
    85| */
    86|export async function writeIndexFile(filePath: string, data: unknown): Promise<void> {
    87|  const dir = path.dirname(filePath);
    88|  await fs.mkdir(dir, { recursive: true });
    89|  const tmpPath = `${filePath}.${randomUUID()}.tmp`;
    90|  await fs.writeFile(tmpPath, JSON.stringify(data, null, 2), "utf-8");
    91|  await fs.rename(tmpPath, filePath);
    92|}
    93|
    94|/**
    95| * Full reindex for one project directory.
    96| * Reads PROJECT.md, all task files, and queue.md; writes all .index/ JSON files.
    97| * Returns an array of SyncEvent objects describing what was written.
    98| * Invalid frontmatter is skipped with a warning (D-09, PARSE-03).
    99| */
   100|export async function generateAllIndexes(projectDir: string): Promise<SyncEvent[]> {
   101|  const projectName = path.basename(projectDir);
   102|  const events: SyncEvent[] = [];
   103|  const indexDir = path.join(projectDir, ".index");
   104|  const tasksIndexDir = path.join(indexDir, "tasks");
   105|
   106|  // Ensure .index/ directories exist
   107|  await fs.mkdir(tasksIndexDir, { recursive: true });
   108|
   109|  // 1. Parse and write PROJECT.md index
   110|  let columns: string[] = ["Backlog", "In Progress", "Review", "Done"];
   111|  try {
   112|    const projectContent = await fs.readFile(path.join(projectDir, "PROJECT.md"), "utf-8");
   113|    const result = parseProjectFrontmatter(projectContent, "PROJECT.md");
   114|    if (result.success) {
   115|      columns = result.data.columns;
   116|      const projectIndex = generateProjectIndex(result.data);
   117|      await writeIndexFile(path.join(indexDir, "project.json"), projectIndex);
   118|      events.push({ type: "project:changed", project: projectName });
   119|    }
   120|  } catch {
   121|    // PROJECT.md missing or unreadable -- skip
   122|  }
   123|
   124|  // 2. Parse all task files
   125|  const validTasks: TaskFrontmatter[] = [];
   126|  const tasksDir = path.join(projectDir, "tasks");
   127|  let taskFiles: string[] = [];
   128|  try {
   129|    const entries = await fs.readdir(tasksDir);
   130|    taskFiles = entries.filter((f) => /^TASK-\d+\.md$/.test(f)).toSorted();
   131|  } catch {
   132|    // tasks/ missing -- no tasks to index
   133|  }
   134|
   135|  for (const taskFile of taskFiles) {
   136|    const filePath = path.join(tasksDir, taskFile);
   137|    try {
   138|      const content = await fs.readFile(filePath, "utf-8");
   139|      const result = parseTaskFrontmatter(content, taskFile);
   140|      if (result.success) {
   141|        validTasks.push(result.data);
   142|        const taskIndex = generateTaskIndex(result.data);
   143|        await writeIndexFile(path.join(tasksIndexDir, `${result.data.id}.json`), taskIndex);
   144|        events.push({ type: "task:changed", project: projectName, taskId: result.data.id });
   145|      }
   146|      // Invalid frontmatter: skip silently (D-09)
   147|    } catch {
   148|      // Unreadable file: skip
   149|    }
   150|  }
   151|
   152|  // 3. Generate and write board index from valid tasks
   153|  const boardIndex = generateBoardIndex(validTasks, columns);
   154|  await writeIndexFile(path.join(indexDir, "board.json"), boardIndex);
   155|
   156|  // 4. Parse and write queue index
   157|  try {
   158|    const queueContent = await fs.readFile(path.join(projectDir, "queue.md"), "utf-8");
   159|    const parsedQueue = parseQueue(queueContent, "queue.md");
   160|    const queueIndex = generateQueueIndex(parsedQueue);
   161|    await writeIndexFile(path.join(indexDir, "queue.json"), queueIndex);
   162|    events.push({ type: "queue:changed", project: projectName });
   163|  } catch {
   164|    // queue.md missing or unreadable -- skip
   165|  }
   166|
   167|  events.push({ type: "reindex:complete", project: projectName });
   168|  return events;
   169|}
