    27|  async start(): Promise<void> {
    28|    this.syncService = new ProjectSyncService(this.projectsRoot);
    29|    this.syncHandler = (event: SyncEvent) => this.handleSyncEvent(event);
    30|    this.syncService.on("sync", this.syncHandler);
    31|    await this.syncService.start();
    32|  }
    33|
    34|  async stop(): Promise<void> {
    35|    if (this.syncService) {
    36|      if (this.syncHandler) {
    37|        this.syncService.removeListener("sync", this.syncHandler);
    38|        this.syncHandler = null;
    39|      }
    40|      await this.syncService.stop();
    41|      this.syncService = null;
    42|    }
    43|  }
    44|
    45|  private handleSyncEvent(event: SyncEvent): void {
    46|    switch (event.type) {
    47|      case "project:changed":
    48|        this.broadcast("projects.changed", { project: event.project });
    49|        break;
    50|      case "task:changed":
    51|      case "task:deleted":
    52|        this.broadcast("projects.board.changed", { project: event.project });
    53|        break;
    54|      case "queue:changed":
    55|        this.broadcast("projects.queue.changed", { project: event.project });
    56|        break;
    57|      case "reindex:complete":
    58|        // Internal-only event; no broadcast needed
    59|        break;
