    83|
    84|export async function loadProjects(state: ProjectsState): Promise<void> {
    85|  if (!state.client || !state.connected) return;
    86|  if (state.projectsLoading) return;
    87|
    88|  state.projectsLoading = true;
    89|  state.projectsError = null;
    90|
    91|  try {
    92|    const res = await state.client.request<{ projects: ProjectListEntry[] }>(
    93|      "projects.list",
    94|      {},
    95|    );
    96|    state.projectsList = res.projects ?? [];
    97|
    98|    // Fetch boards and queues in parallel for task counts and agent counts
    99|    const names = state.projectsList.map((p) => p.name);
   100|    const [boards, queues] = await Promise.all([
   101|      Promise.all(
   102|        names.map(async (name) => {
   103|          try {
   104|            const b = await state.client!.request<{ board: BoardIndex }>(
   105|              "projects.board.get",
   106|              { project: name },
   107|            );
   108|            return [name, b.board] as const;
   109|          } catch {
   110|            return null;
   111|          }
   112|        }),
   113|      ),
   114|      Promise.all(
