   118|              "projects.queue.get",
   119|              { project: name },
   120|            );
   121|            return [name, q.queue] as const;
   122|          } catch {
   123|            return null;
   124|          }
   125|        }),
   126|      ),
   127|    ]);
   128|
   129|    const boardMap: Record<string, BoardIndex> = {};
   130|    for (const entry of boards) if (entry) boardMap[entry[0]] = entry[1];
   131|    state.projectsBoards = boardMap;
   132|
   133|    const queueMap: Record<string, QueueIndex> = {};
   134|    for (const entry of queues) if (entry) queueMap[entry[0]] = entry[1];
   135|    state.projectsQueues = queueMap;
   136|  } catch (err) {
   137|    state.projectsError = String(err);
   138|  } finally {
   139|    state.projectsLoading = false;
   140|  }
