{"content": "     1|import { html, nothing } from "lit";
     2|import type { BoardIndex, BoardTaskEntry, CheckpointInfo } from "../controllers/projects.ts";
     3|
     4|export type KanbanBoardProps = {
     5|  board: BoardIndex | null;
     6|  loading: boolean;
     7|  error: string | null;
     8|  expandedTaskId: string | null;
     9|  checkpoint: CheckpointInfo | null;
    10|  checkpointLoading: boolean;
    11|  allTasks: BoardTaskEntry[];
    12|  onTogglePeek: (taskId: string) => void;
    13|};
    14|
    15|export function renderKanbanBoard(props: KanbanBoardProps) {
    16|  if (props.loading) return renderBoardSkeleton();
    17|  if (props.error) return html`<div class="projects-error">${props.error}</div>`;
    18|  if (!props.board) return html`<div class="projects-board-column__empty">No tasks in this project</div>`;
    19|
    20|  const columns = props.board.columns;
    21|  if (columns.length === 0) return html`<div class="projects-board-column__empty">No columns configured</div>`;
    22|
    23|  return html`
    24|    <div class="projects-board">
    25|      ${columns.map((col) => renderColumn(col, props))}
    26|    </div>
    27|  `;
    28|}
    29|
    30|function renderColumn(column: { name: string; tasks: BoardTaskEntry[] }, props: KanbanBoardProps) {
    31|  return html`
    32|    <div class="projects-board-column">
    33|      <div class="projects-board-column__header">
    34|        <span class="projects-board-column__name">${column.name}</span>
    35|        <span class="projects-board-column__count">${column.tasks.length}</span>
    36|      </div>
    37|      <div class="projects-board-column__cards">
    38|        ${column.tasks.length === 0
    39|          ? html`<div class="projects-board-column__empty">No tasks</div>`
    40|          : column.tasks.map((task) => renderCard(task, props))}
    41|      </div>
    42|    </div>
    43|  `;
    44|}
    45|
    46|function renderCard(task: BoardTaskEntry, props: KanbanBoardProps) {
    47|  const priorityClass = `projects-board-card--${task.priority || "low"}`;
    48|  const isBlocked = hasUnfinishedDeps(task, props.allTasks);
    49|  const isExpanded = props.expandedTaskId === task.id;
    50|
    51|  return html`
    52|    <div class="${`projects-board-card ${priorityClass}`}">
    53|      <div class="projects-board-card__top">
    54|        <span class="projects-board-card__id">${task.id}</span>
    55|        ${isBlocked ? html`
    56|          <span class="projects-board-card__blocked">
    57|            <svg viewBox="0 0 16 16" fill="currentColor" width="12" height="12"><path d="M8 1a4 4 0 0 0-4 4v2H3a1 1 0 0 0-1 1v6a1 1 0 0 0 1 1h10a1 1 0 0 0 1-1V8a1 1 0 0 0-1-1h-1V5a4 4 0 0 0-4-4zm2 6H6V5a2 2 0 1 1 4 0v2z"/></svg>
    58|            Blocked
    59|          </span>
    60|        ` : nothing}
    61|      </div>
    62|      <div class="projects-board-card__title">${task.title}</div>
    63|      ${task.claimed_by ? html`<div class="projects-board-card__assignee">${task.claimed_by}</div>` : nothing}
    64|      ${task.claimed_by ? renderAgentBar(task, props) : nothing}
    65|    </div>
    66|    ${isExpanded ? renderPeekPanel(props) : nothing}
    67|  `;
    68|}
    69|
    70|function hasUnfinishedDeps(task: BoardTaskEntry, allTasks: BoardTaskEntry[]): boolean {
    71|  if (!task.depends_on || task.depends_on.length === 0) return false;
    72|  return task.depends_on.some((depId) => {
    73|    const dep = allTasks.find((t) => t.id === depId);
    74|    return dep && dep.status !== "Done" && dep.status !== "done";
    75|  });
    76|}
    77|
    78|function renderAgentBar(task: BoardTaskEntry, props: KanbanBoardProps) {
    79|  return html`
    80|    <div class="projects-board-card__agent" @click=${() => props.onTogglePeek(task.id)}>
    81|      <span class="projects-board-card__agent-dot"></span>
    82|      <span class="projects-board-card__agent-name">${task.claimed_by}</span>
    83|    </div>
    84|  `;
    85|}
    86|
