{"content": "     1|import { html, nothing } from "lit";
     2|import type { ProjectListEntry, BoardIndex, QueueIndex } from "../controllers/projects.ts";
     3|import { formatRelativeTimestamp } from "../format.ts";
     4|
     5|/**
     6| * Widget 1: Project status overview with key stats.
     7| * Accepts optional board to derive total task count (plan says "from board").
     8| */
     9|export function renderProjectStatusWidget(
    10|  project: ProjectListEntry,
    11|  board?: BoardIndex | null,
    12|) {
    13|  const totalTasks = board
    14|    ? board.columns.reduce((sum, col) => sum + col.tasks.length, 0)
    15|    : 0;
    16|  const statusOk = project.status.toLowerCase() === "active";
    17|  const updatedTs = project.updated ?? project.indexedAt;
    18|  const updatedMs = updatedTs ? new Date(updatedTs).getTime() : null;
    19|
    20|  return html`
    21|    <div class="card projects-widget stagger-1">
    22|      <div class="card-title">Status</div>
    23|      <div class="stat-grid">
    24|        <div class="stat-cell">
    25|          <div class="stat-label">STATUS</div>
    26|          <div class="stat-value ${statusOk ? "ok" : "warn"}">${project.status}</div>
    27|        </div>
    28|        <div class="stat-cell">
    29|          <div class="stat-label">TASKS</div>
    30|          <div class="stat-value">${totalTasks}</div>
    31|        </div>
    32|        <div class="stat-cell">
    33|          <div class="stat-label">OWNER</div>
    34|          <div class="stat-value">${project.owner ?? "\u2014"}</div>
    35|        </div>
    36|        <div class="stat-cell">
    37|          <div class="stat-label">UPDATED</div>
    38|          <div class="stat-value">${updatedMs ? formatRelativeTimestamp(updatedMs) : "n/a"}</div>
    39|        </div>
    40|      </div>
    41|    </div>
    42|  `;
    43|}
    44|
    45|/**
    46| * Widget 2: Task counts stacked bar with per-column breakdown.
    47| */
    48|export function renderTaskCountsWidget(board: BoardIndex | null) {
    49|  const columns = board?.columns ?? [];
    50|  const total = columns.reduce((sum, col) => sum + col.tasks.length, 0);
    51|
    52|  return html`
    53|    <div class="card projects-widget stagger-2">
    54|      <div class="card-title">Tasks</div>
    55|      ${total === 0
    56|        ? html`<div class="muted">No tasks</div>`
    57|        : html`
    58|            <div class="projects-bar">
    59|              ${columns
    60|                .filter((col) => col.tasks.length > 0)
    61|                .map((col) => {
    62|                  const pct = (col.tasks.length / total) * 100;
    63|                  const modifier = columnModifier(col.name);
    64|                  return html`
    65|                    <div
    66|                      class="projects-bar__segment ${modifier}"
    67|                      style="flex-basis: ${pct}%"
    68|                    >${col.tasks.length}</div>
    69|                  `;
    70|                })}
    71|            </div>
    72|            <div class="projects-bar-legend">
    73|              ${columns
    74|                .filter((col) => col.tasks.length > 0)
    75|                .map(
    76|                  (col) => html`
    77|                    <span class="projects-bar-legend__item">
    78|                      <span class="projects-bar-legend__dot ${columnModifier(col.name)}"></span>
    79|                      ${col.tasks.length} ${col.name}
    80|                    </span>
    81|                  `,
    82|                )}
    83|            </div>
    84|          `}
    85|    </div>
    86|  `;
    87|}
    88|
    89|/**
    90| * Widget 3: Active agents with pulsing status dots.
    91| */
    92|export function renderActiveAgentsWidget(queue: QueueIndex | null) {
    93|  const claimed = queue?.claimed ?? [];
    94|
    95|  return html`
    96|    <div class="card projects-widget stagger-3">
    97|      <div class="card-title">Active Agents</div>
    98|      ${claimed.length === 0
    99|        ? html`
   100|            <div class="projects-empty">
   101|              <div class="projects-empty__title">No active agents</div>
   102|              <div class="projects-empty__hint">
   103|                No agents are currently working on tasks in this project.
   104|              </div>
   105|            </div>
   106|          `
   107|        : claimed.map((entry) => {
   108|            const agentName =
   109|              entry.metadata.agent ?? entry.metadata.claimed_by ?? "Unknown";
   110|            const claimedAt = entry.metadata.claimed_at
   111|              ? new Date(entry.metadata.claimed_at).getTime()
   112|              : null;
   113|            return html`
   114|              <div class="projects-agent-row">
   115|                <span class="statusDot ok"></span>
   116|                <span class="projects-agent-name">${agentName}</span>
   117|                <span class="projects-agent-task">${entry.taskId}</span>
   118|                <span class="projects-agent-time">
   119|                  ${claimedAt ? formatRelativeTimestamp(claimedAt) : ""}
   120|                </span>
   121|              </div>
   122|            `;
   123|          })}
   124|    </div>
   125|  `;
   126|}
   127|
   128|/**
   129| * Widget 4: Recent activity derived from board task positions.
   130| *
   131| * Note (D-11): The gateway RPC responses do not include task file log entries.
   132| * This widget shows task state changes derived from board column positions as
   133| * a pragmatic approximation. Full log-entry activity requires a future endpoint.
   134| */
   135|export function renderRecentActivityWidget(
   136|  board: BoardIndex | null,
   137|  queue: QueueIndex | null,
   138|) {
   139|  const columns = board?.columns ?? [];
   140|  const allEmpty = columns.every((col) => col.tasks.length === 0);
   141|
   142|  if (!board || allEmpty) {
   143|    return html`
   144|      <div class="card projects-widget stagger-4">
   145|        <div class="card-title">Recent Activity</div>
   146|        <div class="projects-empty">
   147|          <div class="projects-empty__title">No recent activity</div>
   148|          <div class="projects-empty__hint">
   149|            Task changes and agent actions will appear here.
   150|          </div>
   151|        </div>
   152|      </div>
   153|    `;
   154|  }
   155|
   156|  // Build activity entries from board tasks, sorted by column priority
   157|  // (In Progress first, Done last), limited to 10 entries.
   158|  const COLUMN_PRIORITY: Record<string, number> = {
   159|    "in progress": 0,
   160|    review: 1,
   161|    backlog: 2,
   162|    blocked: 3,
   163|    done: 4,
   164|  };
   165|
   166|  type ActivityEntry = {
   167|    taskId: string;
   168|    title: string;
   169|    claimedBy: string;
   170|    columnName: string;
   171|    priority: number;
   172|  };
   173|
   174|  const entries: ActivityEntry[] = [];
   175|  for (const col of columns) {
   176|    const priority = COLUMN_PRIORITY[col.name.toLowerCase()] ?? 2;
   177|    for (const task of col.tasks) {
   178|      entries.push({
   179|        taskId: task.id,
   180|        title: task.title,
   181|        claimedBy: task.claimed_by ?? "System",
   182|        columnName: col.name,
   183|        priority,
   184|      });
   185|    }
   186|  }
   187|  entries.sort((a, b) => a.priority - b.priority);
   188|  const visible = entries.slice(0, 10);
   189|
   190|  const indexedAtMs = board.indexedAt ? new Date(board.indexedAt).getTime() : null;
   191|
   192|  return html`
   193|    <div class="card projects-widget stagger-4">
   194|      <div class="card-title">Recent Activity</div>
   195|      ${visible.map(
   196|        (entry) => html`
   197|          <div class="projects-activity-row">
   198|            <span class="projects-activity-time">
   199|              ${indexedAtMs ? formatRelativeTimestamp(indexedAtMs) : ""}
   200|            </span>
   201|            <span class="projects-activity-agent">${entry.claimedBy}</span>
   202|            <span class="projects-activity-action">
   203|              ${entry.taskId}: ${entry.title}
   204|              <span class="muted">(${entry.columnName})</span>
   205|            </span>
   206|          </div>
   207|        `,
   208|      )}
   209|    </div>
   210|  `;
   211|}
   212|
   213|// --- Helpers ---
   214|
   215|/** Map column name to a BEM modifier class for the stacked bar segment. */
   216|function columnModifier(name: string): string {
   217|  const slug = name.toLowerCase().replace(/\s+/g, "-");
   218|  return `projects-bar__segment--${slug}`;
   219|}
