{"content": "     1|import { html, nothing } from "lit";
     2|import type { ProjectListEntry, BoardIndex, QueueIndex } from "../controllers/projects.ts";
     3|
     4|export type ProjectsListProps = {
     5|  loading: boolean;
     6|  error: string | null;
     7|  projects: ProjectListEntry[] | null;
     8|  boards: Record<string, BoardIndex>;
     9|  queues: Record<string, QueueIndex>;
    10|  onSelectProject: (name: string) => void;
    11|  onRefresh: () => void;
    12|};
    13|
    14|/** Render the project list table with status badges, task counts, and agent counts. */
    15|export function renderProjectsList(props: ProjectsListProps) {
    16|  // Error state
    17|  if (props.error) {
    18|    return html`
    19|      <div class="projects-error">
    20|        Failed to load project data. Try refreshing the page.
    21|        <button class="btn btn-sm" @click=${props.onRefresh}>Retry</button>
    22|      </div>
    23|    `;
    24|  }
    25|
    26|  // Loading state (projects is null and no error)
    27|  if (props.projects == null) {
    28|    return html`
    29|      <div class="data-table-wrapper">
    30|        <div class="projects-skeleton-row"></div>
    31|        <div class="projects-skeleton-row"></div>
    32|        <div class="projects-skeleton-row"></div>
    33|        <div class="projects-skeleton-row"></div>
    34|      </div>
    35|    `;
    36|  }
    37|
    38|  // Filter out sub-projects (names containing "/")
    39|  const topLevel = props.projects.filter((p) => !p.name.includes("/"));
    40|
    41|  // Empty state
    42|  if (topLevel.length === 0) {
    43|    return html`
    44|      <div class="projects-empty">
    45|        <div class="projects-empty__title">No projects yet</div>
    46|        <div class="projects-empty__hint">
    47|          Create your first project to start tracking tasks and agent activity.
    48|        </div>
    49|        <code class="projects-empty__command">openclaw projects create &lt;name&gt;</code>
    50|      </div>
    51|    `;
    52|  }
    53|
    54|  return html`
    55|    <div class="data-table-wrapper">
    56|      <div class="data-table-container">
    57|        <table class="data-table">
    58|          <thead>
    59|            <tr>
    60|              <th style="flex:2">NAME</th>
    61|              <th style="width:80px">STATUS</th>
    62|              <th style="flex:1">TASKS</th>
    63|              <th style="width:60px">AGENTS</th>
    64|              <th class="projects-col-owner" style="width:100px">OWNER</th>
    65|            </tr>
    66|          </thead>
    67|          <tbody>
    68|            ${topLevel.map((project) => {
    69|              const board = props.boards[project.name];
    70|              const queue = props.queues[project.name];
    71|              const agentCount = queue?.claimed?.length ?? 0;
    72|              const statusClass = resolveStatusClass(project.status);
    73|
    74|              return html`
    75|                <tr
    76|                  class="list-item-clickable"
    77|                  @click=${() => props.onSelectProject(project.name)}
    78|                >
    79|                  <td style="flex:2">${project.name}</td>
    80|                  <td style="width:80px">
    81|                    <span class="projects-badge ${statusClass}">${project.status}</span>
    82|                  </td>
    83|                  <td style="flex:1">
    84|                    <span class="projects-task-counts">
    85|                      ${renderTaskCounts(board)}
    86|                    </span>
    87|                  </td>
    88|                  <td style="width:60px">${agentCount}</td>
    89|                  <td class="projects-col-owner" style="width:100px">
    90|                    ${project.owner ?? "\u2014"}
    91|                  </td>
    92|                </tr>
    93|              `;
    94|            })}
    95|          </tbody>
    96|        </table>
    97|      </div>
    98|    </div>
    99|  `;
   100|}
   101|
   102|/** Map project status to badge modifier class. */
   103|function resolveStatusClass(status: string): string {
   104|  const normalized = status.toLowerCase();
   105|  if (normalized === "active") return "projects-badge--active";
   106|  if (normalized === "paused") return "projects-badge--paused";
   107|  if (normalized === "complete" || normalized === "completed") return "projects-badge--complete";
   108|  return "projects-badge--active";
   109|}
   110|
   111|/** Render per-column task counts from board data. */
   112|function renderTaskCounts(board: BoardIndex | undefined) {
   113|  if (!board?.columns?.length) return html`<span class="muted">0</span>`;
   114|
   115|  return board.columns
   116|    .filter((col) => col.tasks.length > 0)
   117|    .map(
   118|      (col) =>
   119|        html`<span class="projects-task-count">${col.tasks.length} ${col.name}</span>`,
   120|    );
   121|}
   122|", "total_lines": 121, "file_size": 4176, "truncated": false, "is_binary": false, "is_image": false}

