     4|/**
     5| * Generate PROJECT.md content with valid YAML frontmatter and defaults
     6| * filled by the Zod schema (columns, dashboard widgets, status).
     7| */
     8|export function generateProjectMd(opts: {
     9|  name: string;
    10|  description?: string;
    11|  owner?: string;
    12|}): string {
    13|  const today = new Date().toISOString().split("T")[0];
    14|  const data = ProjectFrontmatterSchema.parse({
    15|    name: opts.name,
    16|    description: opts.description,
    17|    owner: opts.owner,
    18|    created: today,
    19|    updated: today,
    20|  });
    21|
    22|  const yaml = YAML.stringify(data, { schema: "core" });
    23|  const desc = opts.description ?? "";
    24|  return `---\n${yaml}---\n\n# ${opts.name}\n\n${desc}\n`;
    25|}
