     2|import * as p from "@clack/prompts";
     3|import { resolveRequiredHomeDir } from "../infra/home-dir.js";
     4|import { ProjectManager } from "../projects/scaffold.js";
     5|import { ProjectSyncService } from "../projects/sync-service.js";
     6|import type { OutputRuntimeEnv } from "../runtime.js";
     7|import { defaultRuntime } from "../runtime.js";
     8|
     9|export type ProjectsCreateOptions = {
    10|  name?: string;
    11|  description?: string;
    12|  owner?: string;
    13|  parent?: string;
    14|  json?: boolean;
    15|};
    16|
    17|type ProjectsCreateContext = {
    18|  homeDir?: string;
    19|};
    20|
    21|export async function projectsCreateCommand(
    22|  opts: ProjectsCreateOptions,
    23|  context: ProjectsCreateContext = {},
    24|  runtime: OutputRuntimeEnv = defaultRuntime,
    25|): Promise<void> {
    26|  let { name, description, owner } = opts;
    27|
    28|  // Interactive prompts when name not provided
    29|  if (!name) {
    30|    const nameResult = await p.text({ message: "Project name:" });
    31|    if (p.isCancel(nameResult)) {
    32|      return;
    33|    }
    34|    name = nameResult;
    35|
    36|    const descResult = await p.text({ message: "Description (optional):" });
    37|    if (!p.isCancel(descResult)) {
    38|      description = descResult;
    39|    }
    40|
    41|    const ownerResult = await p.text({ message: "Owner (optional):" });
    42|    if (!p.isCancel(ownerResult)) {
    43|      owner = ownerResult;
    44|    }
    45|  }
    46|
    47|  const manager = new ProjectManager(context.homeDir);
    48|
    49|  try {
    50|    let projectDir: string;
    51|    if (opts.parent) {
    52|      projectDir = await manager.createSubProject({
    53|        name,
    54|        parent: opts.parent,
    55|        description,
    56|        owner,
    57|      });
    58|    } else {
    59|      projectDir = await manager.create({ name, description, owner });
    60|    }
    61|
    62|    if (opts.json) {
    63|      runtime.writeJson({ path: projectDir, name });
    64|    } else {
    65|      runtime.log(`Created project at ${projectDir}`);
    66|    }
    67|  } catch (err: unknown) {
    68|    const message = err instanceof Error ? err.message : String(err);
    69|    runtime.error(message);
    70|
    71|    // List available projects as suggestions on duplicate error
    72|    if (message.includes("already exists")) {
    73|      try {
    74|        const home = context.homeDir ?? resolveRequiredHomeDir();
    75|        const projectsRoot = path.join(home, ".openclaw", "projects");
    76|        const syncService = new ProjectSyncService(projectsRoot);
    77|        const projects = await syncService.discoverProjects();
    78|        if (projects.length > 0) {
    79|          const names = projects.map((dir) => path.basename(dir));
    80|          runtime.error(`Existing projects: ${names.join(", ")}`);
    81|        }
    82|      } catch {
    83|        // Ignore discovery errors
    84|      }
    85|    }
    86|
    87|    runtime.exit(1);
    88|  }
