{"content": "     1|import fs from "node:fs/promises";
     2|import path from "node:path";
     3|import { resolveRequiredHomeDir } from "../infra/home-dir.js";
     4|import { parseProjectFrontmatter } from "../projects/frontmatter.js";
     5|import { ProjectSyncService } from "../projects/sync-service.js";
     6|import type { OutputRuntimeEnv } from "../runtime.js";
     7|import { defaultRuntime } from "../runtime.js";
     8|import { renderTable } from "../terminal/table.js";
     9|
    10|export type ProjectsListOptions = {
    11|  json?: boolean;
    12|};
    13|
    14|type ProjectsListContext = {
    15|  homeDir?: string;
    16|};
    17|
    18|export async function projectsListCommand(
    19|  opts: ProjectsListOptions = {},
    20|  context: ProjectsListContext = {},
    21|  runtime: OutputRuntimeEnv = defaultRuntime,
    22|): Promise<void> {
    23|  const home = context.homeDir ?? resolveRequiredHomeDir();
    24|  const projectsRoot = path.join(home, ".openclaw", "projects");
    25|  const syncService = new ProjectSyncService(projectsRoot);
    26|  const projectDirs = await syncService.discoverProjects();
    27|
    28|  if (projectDirs.length === 0) {
    29|    runtime.log("No projects found. Create one with: openclaw projects create <name>");
    30|    return;
    31|  }
    32|
    33|  const summaries: Array<{
    34|    name: string;
    35|    status: string;
    36|    tasks: string;
    37|    owner: string;
    38|  }> = [];
    39|
    40|  for (const projectDir of projectDirs) {
    41|    let name = path.basename(projectDir);
    42|    let status = "unknown";
    43|    let owner = "";
    44|
    45|    try {
    46|      const content = await fs.readFile(path.join(projectDir, "PROJECT.md"), "utf-8");
    47|      const result = parseProjectFrontmatter(content, "PROJECT.md");
    48|      if (result.success) {
    49|        name = result.data.name;
    50|        status = result.data.status;
    51|        owner = result.data.owner ?? "";
    52|      }
    53|    } catch {
    54|      // Use defaults from directory name
    55|    }
