    17|  homeDir?: string;
    18|};
    19|
    20|export async function projectsStatusCommand(
    21|  opts: ProjectsStatusOptions,
    22|  context: ProjectsStatusContext = {},
    23|  runtime: OutputRuntimeEnv = defaultRuntime,
    24|): Promise<void> {
    25|  const home = context.homeDir ?? resolveRequiredHomeDir();
    26|  const projectsRoot = path.join(home, ".openclaw", "projects");
    27|  const projectDir = path.join(projectsRoot, opts.name);
    28|
    29|  // Check if project exists
    30|  try {
    31|    await fs.access(projectDir);
    32|  } catch {
    33|    runtime.error(`Project not found: ${opts.name}`);
    34|
    35|    // List available projects as suggestions
    36|    try {
    37|      const syncService = new ProjectSyncService(projectsRoot);
    38|      const projects = await syncService.discoverProjects();
    39|      if (projects.length > 0) {
    40|        const names = projects.map((d) => path.basename(d));
    41|        runtime.error(`Available projects: ${names.join(", ")}`);
    42|      }
    43|    } catch {
    44|      // Ignore discovery errors
    45|    }
    46|
    47|    runtime.exit(1);
    48|    return;
    49|  }
    50|
    51|  // Read project frontmatter
    52|  let projectName = opts.name;
    53|  let projectStatus = "unknown";
    54|  let projectDescription: string | undefined;
    55|
    56|  try {
    57|    const content = await fs.readFile(path.join(projectDir, "PROJECT.md"), "utf-8");
    58|    const result = parseProjectFrontmatter(content, "PROJECT.md");
    59|    if (result.success) {
    60|      projectName = result.data.name;
    61|      projectStatus = result.data.status;
    62|      projectDescription = result.data.description;
    63|    }
    64|  } catch {
    65|    // Use defaults
    66|  }
    67|
    68|  // Read and group tasks by status
    69|  const taskCounts: Record<string, number> = {};
    70|  try {
    71|    const tasksDir = path.join(projectDir, "tasks");
    72|    const entries = await fs.readdir(tasksDir);
    73|    const taskFiles = entries.filter((f) => /^TASK-\d+\.md$/.test(f));
    74|
    75|    for (const taskFile of taskFiles) {
    76|      try {
    77|        const content = await fs.readFile(path.join(tasksDir, taskFile), "utf-8");
    78|        const result = parseTaskFrontmatter(content, taskFile);
    79|        if (result.success) {
    80|          const status = result.data.status;
    81|          taskCounts[status] = (taskCounts[status] ?? 0) + 1;
    82|        }
    83|      } catch {
    84|        // Skip unreadable task files
    85|      }
    86|    }
    87|  } catch {
    88|    // tasks/ missing
    89|  }
    90|
    91|  // Read queue for claimed tasks / active agents
    92|  const activeAgents: Array<{ agent: string; taskId: string }> = [];
    93|  try {
    94|    const queueContent = await fs.readFile(path.join(projectDir, "queue.md"), "utf-8");
    95|    const parsedQueue = parseQueue(queueContent, "queue.md");
    96|    for (const entry of parsedQueue.claimed) {
    97|      const agent = entry.metadata.agent;
    98|      if (agent) {
    99|        activeAgents.push({ agent, taskId: entry.taskId });
   100|      }
   101|    }
   102|  } catch {
