     8|
     9|export type ProjectsReindexOptions = {
    10|  json?: boolean;
    11|};
    12|
    13|type ProjectsReindexContext = {
    14|  homeDir?: string;
    15|};
    16|
    17|/** Check if a PID is alive by sending signal 0. */
    18|function isPidAlive(pid: number): boolean {
    19|  try {
    20|    process.kill(pid, 0);
    21|    return true;
    22|  } catch {
    23|    return false;
    24|  }
    25|}
    26|
    27|export async function projectsReindexCommand(
    28|  opts: ProjectsReindexOptions = {},
    29|  context: ProjectsReindexContext = {},
    30|  runtime: OutputRuntimeEnv = defaultRuntime,
    31|): Promise<void> {
    32|  const home = context.homeDir ?? resolveRequiredHomeDir();
    33|  const projectsRoot = path.join(home, ".openclaw", "projects");
    34|  const syncService = new ProjectSyncService(projectsRoot);
    35|  const projectDirs = await syncService.discoverProjects();
    36|
    37|  if (projectDirs.length === 0) {
    38|    runtime.log("No projects found. Create one with: openclaw projects create <name>");
    39|    return;
    40|  }
    41|
    42|  // Reindex each project
    43|  for (const projectDir of projectDirs) {
    44|    const projectName = path.basename(projectDir);
    45|    await generateAllIndexes(projectDir);
    46|
    47|    // Count task files
    48|    let taskCount = 0;
    49|    try {
    50|      const entries = await fs.readdir(path.join(projectDir, "tasks"));
    51|      taskCount = entries.filter((e) => /^TASK-\d+\.md$/.test(e)).length;
    52|    } catch {
    53|      // tasks/ missing
    54|    }
    55|
    56|    runtime.log(`Reindexed: ${projectName} (${taskCount} tasks)`);
    57|  }
    58|
    59|  // Scan and clear stale lock files
    60|  let locksCleared = 0;
    61|  const now = Date.now();
    62|  const staleLockThresholdMs = 60_000;
    63|
    64|  for (const projectDir of projectDirs) {
    65|    try {
    66|      const entries = await findLockFiles(projectDir);
    67|      for (const lockPath of entries) {
    68|        try {
    69|          const content = await fs.readFile(lockPath, "utf-8");
    70|          const lockData = JSON.parse(content) as { pid?: number; timestamp?: number };
    71|
    72|          const isStale = !lockData.timestamp || now - lockData.timestamp > staleLockThresholdMs;
    73|          const isDead = !lockData.pid || !isPidAlive(lockData.pid);
    74|
    75|          if (isStale || isDead) {
    76|            await fs.unlink(lockPath);
    77|            locksCleared++;
    78|          }
    79|        } catch {
    80|          // Unreadable or malformed lock file — remove it
    81|          try {
    82|            await fs.unlink(lockPath);
    83|            locksCleared++;
    84|          } catch {
    85|            // Already gone
    86|          }
    87|        }
    88|      }
    89|    } catch {
    90|      // Skip project on error
    91|    }
    92|  }
    93|
    94|  runtime.log(`Reindexed ${projectDirs.length} project(s). Cleared ${locksCleared} stale lock(s).`);
    95|
    96|  if (opts.json) {
    97|    runtime.writeJson({ projects: projectDirs.length, locksCleared });
    98|  }
    99|}
   100|
   101|/** Recursively find all .lock files under a directory. */
   102|async function findLockFiles(dir: string): Promise<string[]> {
   103|  const results: string[] = [];
   104|  try {
   105|    const entries = await fs.readdir(dir, { withFileTypes: true });
   106|    for (const entry of entries) {
   107|      const fullPath = path.join(dir, entry.name);
   108|      if (entry.isDirectory()) {
   109|        const nested = await findLockFiles(fullPath);
   110|        results.push(...nested);
   111|      } else if (entry.name.endsWith(".lock")) {
   112|        results.push(fullPath);
   113|      }
   114|    }
   115|  } catch {
   116|    // Directory unreadable
   117|  }
   118|  return results;
   119|}
