{"content": "     1|import fs from "node:fs";
     2|import os from "node:os";
     3|import path from "node:path";
     4|import type { AgentBootstrapHookContext } from "../hooks/internal-hooks.js";
     5|import { registerInternalHook } from "../hooks/internal-hooks.js";
     6|import type { WorkspaceBootstrapFileName } from "./workspace.js";
     7|
     8|/**
     9| * Bootstrap hook that injects PROJECT.md for project-scoped channels.
    10| *
    11| * Reads the `project` field from the agent's config entry. If set,
    12| * loads the corresponding PROJECT.md from ~/.openclaw/projects/<name>/PROJECT.md.
    13| *
    14| * Deduplication: if PROJECT.md was already injected by cwd walk-up (D-06),
    15| * this hook skips injection to avoid duplicates. CWD version takes priority.
    16| */
    17|function projectContextBootstrapHandler(context: AgentBootstrapHookContext): void {
    18|  // Skip if PROJECT.md already injected by cwd walk-up (D-06)
    19|  if (context.bootstrapFiles.some((f) => f.name === "PROJECT.md")) {
    20|    return;
    21|  }
    22|
    23|  const projectName = resolveProjectFromConfig(context);
    24|  if (!projectName) {
    25|    return;
    26|  }
    27|
    28|  const projectMdPath = path.join(os.homedir(), ".openclaw", "projects", projectName, "PROJECT.md");
    29|
    30|  try {
    31|    const content = fs.readFileSync(projectMdPath, "utf-8");
    32|    context.bootstrapFiles.push({
    33|      name: "PROJECT.md" as WorkspaceBootstrapFileName,
    34|      path: projectMdPath,
    35|      content,
    36|      missing: false,
    37|    });
    38|  } catch {
    39|    // Project configured but PROJECT.md missing -- silently skip
    40|  }
    41|}
    42|
    43|/**
    44| * Resolve the project name from agent config.
    45| * Looks up the agent by agentId in cfg.agents.list, then reads the `project` field.
    46| */
    47|function resolveProjectFromConfig(context: AgentBootstrapHookContext): string | undefined {
    48|  const cfg = context.cfg;
    49|  if (!cfg) {
    50|    return undefined;
    51|  }
    52|
    53|  // Access agents.list to find the agent's config entry
    54|  const agentsList = (cfg as Record<string, unknown>).agents as
    55|    | { list?: Array<Record<string, unknown>> }
    56|    | undefined;
    57|  if (!agentsList?.list) {
    58|    return undefined;
    59|  }
    60|
    61|  const agentId = context.agentId;
    62|  if (!agentId) {
    63|    return undefined;
    64|  }
    65|
    66|  const agentEntry = agentsList.list.find((a) => a.id === agentId);
    67|  if (agentEntry?.project && typeof agentEntry.project === "string") {
    68|    return agentEntry.project;
    69|  }
    70|
    71|  return undefined;
    72|}
    73|
    74|export function registerProjectContextHook(): void {
    75|  registerInternalHook("agent:bootstrap", (event) => {
    76|    const context = event.context as AgentBootstrapHookContext;
    77|    projectContextBootstrapHandler(context);
    78|  });
    79|}
