     2|import path from "node:path";
     3|import { SettingsManager } from "@mariozechner/pi-coding-agent";
     4|import type { OpenClawConfig } from "../config/config.js";
     5|import { applyMergePatch } from "../config/merge-patch.js";
     6|import { openBoundaryFileSync } from "../infra/boundary-file-read.js";
     7|import { createSubsystemLogger } from "../logging/subsystem.js";
     8|import type { BundleMcpServerConfig } from "../plugins/bundle-mcp.js";
     9|import { normalizePluginsConfig, resolveEffectiveEnableState } from "../plugins/config-state.js";
    10|import { loadPluginManifestRegistry } from "../plugins/manifest-registry.js";
    11|import { isRecord } from "../utils.js";
    12|import { loadEmbeddedPiMcpConfig } from "./embedded-pi-mcp.js";
    13|import { applyPiCompactionSettingsFromConfig } from "./pi-settings.js";
    14|
    15|const log = createSubsystemLogger("embedded-pi-settings");
    16|
    17|export const DEFAULT_EMBEDDED_PI_PROJECT_SETTINGS_POLICY = "sanitize";
    18|export const SANITIZED_PROJECT_PI_KEYS = ["shellPath", "shellCommandPrefix"] as const;
    19|
    20|export type EmbeddedPiProjectSettingsPolicy = "trusted" | "sanitize" | "ignore";
    21|
    22|type PiSettingsSnapshot = ReturnType<SettingsManager["getGlobalSettings"]> & {
    23|  mcpServers?: Record<string, BundleMcpServerConfig>;
    24|};
    25|
    26|function sanitizePiSettingsSnapshot(settings: PiSettingsSnapshot): PiSettingsSnapshot {
    27|  const sanitized = { ...settings };
    28|  // Never allow plugin or workspace-local settings to override shell execution behavior.
    29|  for (const key of SANITIZED_PROJECT_PI_KEYS) {
    30|    delete sanitized[key];
    31|  }
    32|  return sanitized;
    33|}
    34|
    35|function sanitizeProjectSettings(settings: PiSettingsSnapshot): PiSettingsSnapshot {
    36|  return sanitizePiSettingsSnapshot(settings);
    37|}
    38|
    39|function loadBundleSettingsFile(params: {
    40|  rootDir: string;
    41|  relativePath: string;
    42|}): PiSettingsSnapshot | null {
    43|  const absolutePath = path.join(params.rootDir, params.relativePath);
    44|  const opened = openBoundaryFileSync({
    45|    absolutePath,
    46|    rootPath: params.rootDir,
    47|    boundaryLabel: "plugin root",
    48|    rejectHardlinks: true,
    49|  });
    50|  if (!opened.ok) {
    51|    log.warn(`skipping unsafe bundle settings file: ${absolutePath}`);
    52|    return null;
    53|  }
    54|  try {
    55|    const raw = JSON.parse(fs.readFileSync(opened.fd, "utf-8")) as unknown;
    56|    if (!isRecord(raw)) {
    57|      log.warn(`skipping bundle settings file with non-object JSON: ${absolutePath}`);
    58|      return null;
    59|    }
    60|    return sanitizePiSettingsSnapshot(raw as PiSettingsSnapshot);
    61|  } catch (error) {
    62|    log.warn(`failed to parse bundle settings file ${absolutePath}: ${String(error)}`);
    63|    return null;
    64|  } finally {
    65|    fs.closeSync(opened.fd);
    66|  }
    67|}
    68|
    69|export function loadEnabledBundlePiSettingsSnapshot(params: {
    70|  cwd: string;
    71|  cfg?: OpenClawConfig;
    72|}): PiSettingsSnapshot {
    73|  const workspaceDir = params.cwd.trim();
    74|  if (!workspaceDir) {
    75|    return {};
    76|  }
    77|  const registry = loadPluginManifestRegistry({
    78|    workspaceDir,
    79|    config: params.cfg,
    80|  });
    81|  if (registry.plugins.length === 0) {
    82|    return {};
    83|  }
    84|
    85|  const normalizedPlugins = normalizePluginsConfig(params.cfg?.plugins);
    86|  let snapshot: PiSettingsSnapshot = {};
    87|
    88|  for (const record of registry.plugins) {
    89|    const settingsFiles = record.settingsFiles ?? [];
    90|    if (record.format !== "bundle" || settingsFiles.length === 0) {
    91|      continue;
    92|    }
    93|    const enableState = resolveEffectiveEnableState({
    94|      id: record.id,
    95|      origin: record.origin,
    96|      config: normalizedPlugins,
    97|      rootConfig: params.cfg,
    98|    });
    99|    if (!enableState.enabled) {
   100|      continue;
   101|    }
   102|    for (const relativePath of settingsFiles) {
   103|      const bundleSettings = loadBundleSettingsFile({
   104|        rootDir: record.rootDir,
   105|        relativePath,
   106|      });
   107|      if (!bundleSettings) {
   108|        continue;
   109|      }
   110|      snapshot = applyMergePatch(snapshot, bundleSettings) as PiSettingsSnapshot;
   111|    }
   112|  }
   113|
   114|  const embeddedPiMcp = loadEmbeddedPiMcpConfig({
   115|    workspaceDir,
   116|    cfg: params.cfg,
   117|  });
   118|  for (const diagnostic of embeddedPiMcp.diagnostics) {
   119|    log.warn(`bundle MCP skipped for ${diagnostic.pluginId}: ${diagnostic.message}`);
   120|  }
   121|  if (Object.keys(embeddedPiMcp.mcpServers).length > 0) {
   122|    snapshot = applyMergePatch(snapshot, {
   123|      mcpServers: embeddedPiMcp.mcpServers,
   124|    }) as PiSettingsSnapshot;
   125|  }
   126|
   127|  return snapshot;
   128|}
   129|
   130|export function resolveEmbeddedPiProjectSettingsPolicy(
   131|  cfg?: OpenClawConfig,
   132|): EmbeddedPiProjectSettingsPolicy {
   133|  const raw = cfg?.agents?.defaults?.embeddedPi?.projectSettingsPolicy;
   134|  if (raw === "trusted" || raw === "sanitize" || raw === "ignore") {
   135|    return raw;
   136|  }
   137|  return DEFAULT_EMBEDDED_PI_PROJECT_SETTINGS_POLICY;
   138|}
   139|
   140|export function buildEmbeddedPiSettingsSnapshot(params: {
   141|  globalSettings: PiSettingsSnapshot;
   142|  pluginSettings?: PiSettingsSnapshot;
   143|  projectSettings: PiSettingsSnapshot;
   144|  policy: EmbeddedPiProjectSettingsPolicy;
   145|}): PiSettingsSnapshot {
   146|  const effectiveProjectSettings =
   147|    params.policy === "ignore"
   148|      ? {}
   149|      : params.policy === "sanitize"
   150|        ? sanitizeProjectSettings(params.projectSettings)
   151|        : params.projectSettings;
   152|  const withPluginSettings = applyMergePatch(
   153|    params.globalSettings,
   154|    sanitizePiSettingsSnapshot(params.pluginSettings ?? {}),
   155|  ) as PiSettingsSnapshot;
   156|  return applyMergePatch(withPluginSettings, effectiveProjectSettings) as PiSettingsSnapshot;
   157|}
   158|
   159|export function createEmbeddedPiSettingsManager(params: {
   160|  cwd: string;
   161|  agentDir: string;
   162|  cfg?: OpenClawConfig;
   163|}): SettingsManager {
   164|  const fileSettingsManager = SettingsManager.create(params.cwd, params.agentDir);
   165|  const policy = resolveEmbeddedPiProjectSettingsPolicy(params.cfg);
   166|  const pluginSettings = loadEnabledBundlePiSettingsSnapshot({
   167|    cwd: params.cwd,
   168|    cfg: params.cfg,
   169|  });
   170|  const hasPluginSettings = Object.keys(pluginSettings).length > 0;
   171|  if (policy === "trusted" && !hasPluginSettings) {
   172|    return fileSettingsManager;
   173|  }
   174|  const settings = buildEmbeddedPiSettingsSnapshot({
   175|    globalSettings: fileSettingsManager.getGlobalSettings(),
   176|    pluginSettings,
   177|    projectSettings: fileSettingsManager.getProjectSettings(),
   178|    policy,
   179|  });
   180|  return SettingsManager.inMemory(settings);
   181|}
   182|
   183|export function createPreparedEmbeddedPiSettingsManager(params: {
   184|  cwd: string;
   185|  agentDir: string;
   186|  cfg?: OpenClawConfig;
   187|}): SettingsManager {
   188|  const settingsManager = createEmbeddedPiSettingsManager(params);
   189|  applyPiCompactionSettingsFromConfig({
   190|    settingsManager,
   191|    cfg: params.cfg,
   192|  });
   193|  return settingsManager;
   194|}
