     2|  filePath: string;
     3|  message: string;
     4|  issues: Array<{ path: string; message: string; line?: number }>;
     5|}
     6|
     7|export function formatWarning(warning: FrontmatterParseWarning): string {
     8|  const lines = warning.issues.map((i) => {
     9|    const loc = i.line ? `:${i.line}` : "";
    10|    const path = i.path ? ` (${i.path})` : "";
    11|    return `  - ${i.message}${path} at ${warning.filePath}${loc}`;
    12|  });
    13|  return `${warning.message}\n${lines.join("\n")}`;
