{"content": "     1|import YAML from "yaml";
     2|import type { z } from "zod";
     3|import {
     4|  ProjectFrontmatterSchema,
     5|  QueueFrontmatterSchema,
     6|  TaskFrontmatterSchema,
     7|} from "./schemas.js";
     8|import type {
     9|  ParseResult,
    10|  ProjectFrontmatter,
    11|  QueueFrontmatter,
    12|  TaskFrontmatter,
    13|} from "./types.js";
    14|
    15|/**
    16| * Extracts raw YAML content between opening and closing `---` fences.
    17| * Duplicated from src/markdown/frontmatter.ts to maintain independence (PARSE-04).
    18| */
    19|function extractYamlBlock(content: string): string | undefined {
    20|  const normalized = content.replace(/\r\n/g, "\n").replace(/\r/g, "\n");
    21|  if (!normalized.startsWith("---")) {
    22|    return undefined;
    23|  }
    24|  const endIndex = normalized.indexOf("\n---", 3);
    25|  if (endIndex === -1) {
    26|    return undefined;
    27|  }
    28|  return normalized.slice(4, endIndex);
    29|}
    30|
    31|/**
    32| * Parses YAML frontmatter and validates against a Zod schema.
    33| * Returns a discriminated union: success with typed data, or failure with structured error.
    34| */
    35|function parseAndValidate<T>(
    36|  content: string,
    37|  filePath: string,
    38|  schema: z.ZodType<T>,
    39|): ParseResult<T> {
    40|  const block = extractYamlBlock(content);
    41|  if (block === undefined) {
    42|    return {
    43|      success: false,
    44|      error: {
    45|        filePath,
    46|        message: "No frontmatter block found",
    47|        issues: [],
    48|      },
    49|    };
    50|  }
    51|
    52|  let parsed: unknown;
    53|  try {
    54|    // Use "core" schema to avoid YAML 1.1 quirks (e.g. "no" as boolean)
    55|    parsed = YAML.parse(block, { schema: "core" });
    56|  } catch (err: unknown) {
    57|    let line: number | undefined;
    58|    let message = "Unknown YAML error";
    59|    if (err instanceof Error) {
    60|      message = err.message;
    61|    }
    62|    // yaml library errors expose linePos for syntax errors
    63|    if (
    64|      err != null &&
    65|      typeof err === "object" &&
    66|      "linePos" in err &&
    67|      Array.isArray((err as Record<string, unknown>).linePos)
    68|    ) {
    69|      const linePos = (err as Record<string, unknown>).linePos as Array<{
    70|        line: number;
    71|      }>;
    72|      if (linePos.length > 0) {
    73|        line = linePos[0].line;
    74|      }
    75|    }
    76|    return {
    77|      success: false,
    78|      error: {
    79|        filePath,
    80|        message: `YAML parse error: ${message}`,
    81|        issues: [{ path: "", message, line }],
    82|      },
    83|    };
    84|  }
    85|
    86|  // Empty frontmatter block (e.g. "---\n---") parses as null
    87|  const data = parsed ?? {};
    88|
    89|  const result = schema.safeParse(data);
    90|  if (!result.success) {
    91|    const issues = result.error.issues.map((i) => ({
    92|      path: i.path.join("."),
    93|      message: i.message,
    94|    }));
    95|    return {
    96|      success: false,
    97|      error: {
    98|        filePath,
    99|        message: "Schema validation failed",
   100|        issues,
   101|      },
   102|    };
   103|  }
   104|
   105|  return { success: true, data: result.data };
   106|}
   107|
   108|export function parseProjectFrontmatter(
   109|  content: string,
   110|  filePath: string,
   111|): ParseResult<ProjectFrontmatter> {
   112|  return parseAndValidate(content, filePath, ProjectFrontmatterSchema);
   113|}
   114|
   115|export function parseTaskFrontmatter(
   116|  content: string,
   117|  filePath: string,
   118|): ParseResult<TaskFrontmatter> {
   119|  return parseAndValidate(content, filePath, TaskFrontmatterSchema);
   120|}
   121|
   122|export function parseQueueFrontmatter(
   123|  content: string,
   124|  filePath: string,
   125|): ParseResult<QueueFrontmatter> {
   126|  return parseAndValidate(content, filePath, QueueFrontmatterSchema);
   127|}
